    // Precompute suffix minimums: suffixMin[i] = min(nums[i..n-1])
    val suffixMin = Array.ofDim[Long](n)
    var currentMin: Long = Long.MaxValue
    for (i <- n - 1 down to 0) {
      currentMin = math.min(currentMin, arr(i))
      suffixMin(i) = currentMin
    }

    // Iterate and find the smallest stable index
    for (i <- 0 until n) {
      // Unstable value for index i: max(nums[0..i]) - min(nums[i..n-1])
      val unstableValue = prefixMax(i) - suffixMin(i)

      // Check if it is a stable index
      if (unstableValue <= k) {
        return i.toLong
      }
